import logging
import logging.handlers
import os
from pathlib import Path

# Create log directory if it doesn't exist
LOG_DIR = Path('/var/log/application')
LOG_DIR.mkdir(parents=True, exist_ok=True)

# Define log file paths
MAIN_LOG_FILE = LOG_DIR / 'application.log'
ERROR_LOG_FILE = LOG_DIR / 'error.log'
ACCESS_LOG_FILE = LOG_DIR / 'access.log'
DEBUG_LOG_FILE = LOG_DIR / 'debug.log'

# Define log format
DETAILED_FORMAT = logging.Formatter(
    fmt='%(asctime)s - %(name)s - %(levelname)s - [%(filename)s:%(lineno)d] - %(funcName)s() - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

SIMPLE_FORMAT = logging.Formatter(
    fmt='%(asctime)s - %(levelname)s - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

JSON_FORMAT = logging.Formatter(
    fmt='{"timestamp": "%(asctime)s", "level": "%(levelname)s", "logger": "%(name)s", "message": "%(message)s", "module": "%(module)s", "function": "%(funcName)s", "line": %(lineno)d}',
    datefmt='%Y-%m-%d %H:%M:%S'
)

def setup_logging(log_level=logging.INFO, enable_console=False):
    """
    Configure logging with file rotation and multiple handlers
    """
    root_logger = logging.getLogger()
    root_logger.setLevel(logging.DEBUG)
    
    # Clear existing handlers
    root_logger.handlers.clear()
    
    # Main application log handler (rotating by size)
    main_handler = logging.handlers.RotatingFileHandler(
        filename=MAIN_LOG_FILE,
        maxBytes=50 * 1024 * 1024,  # 50 MB
        backupCount=10,
        encoding='utf-8'
    )
    main_handler.setLevel(log_level)
    main_handler.setFormatter(DETAILED_FORMAT)
    root_logger.addHandler(main_handler)
    
    # Error log handler (only errors and critical)
    error_handler = logging.handlers.RotatingFileHandler(
        filename=ERROR_LOG_FILE,
        maxBytes=20 * 1024 * 1024,  # 20 MB
        backupCount=10,
        encoding='utf-8'
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(DETAILED_FORMAT)
    root_logger.addHandler(error_handler)
    
    # Time-based rotating handler (daily rotation)
    timed_handler = logging.handlers.TimedRotatingFileHandler(
        filename=LOG_DIR / 'application_daily.log',
        when='midnight',
        interval=1,
        backupCount=30,  # Keep 30 days
        encoding='utf-8'
    )
    timed_handler.setLevel(log_level)
    timed_handler.setFormatter(DETAILED_FORMAT)
    timed_handler.suffix = '%Y-%m-%d'
    root_logger.addHandler(timed_handler)
    
    # Debug log handler (all levels including debug)
    debug_handler = logging.handlers.RotatingFileHandler(
        filename=DEBUG_LOG_FILE,
        maxBytes=100 * 1024 * 1024,  # 100 MB
        backupCount=5,
        encoding='utf-8'
    )
    debug_handler.setLevel(logging.DEBUG)
    debug_handler.setFormatter(DETAILED_FORMAT)
    root_logger.addHandler(debug_handler)
    
    # Console handler (optional, for development)
    if enable_console:
        console_handler = logging.StreamHandler()
        console_handler.setLevel(log_level)
        console_handler.setFormatter(SIMPLE_FORMAT)
        root_logger.addHandler(console_handler)
    
    return root_logger

def setup_access_logger():
    """
    Setup separate access logger for HTTP requests/API calls
    """
    access_logger = logging.getLogger('access')
    access_logger.setLevel(logging.INFO)
    access_logger.propagate = False
    
    access_handler = logging.handlers.TimedRotatingFileHandler(
        filename=ACCESS_LOG_FILE,
        when='midnight',
        interval=1,
        backupCount=90,  # Keep 90 days
        encoding='utf-8'
    )
    access_handler.setLevel(logging.INFO)
    access_handler.setFormatter(SIMPLE_FORMAT)
    access_logger.addHandler(access_handler)
    
    return access_logger

def setup_json_logger():
    """
    Setup JSON formatted logger for structured logging
    """
    json_logger = logging.getLogger('json')
    json_logger.setLevel(logging.INFO)
    json_logger.propagate = False
    
    json_handler = logging.handlers.RotatingFileHandler(
        filename=LOG_DIR / 'application.json.log',
        maxBytes=50 * 1024 * 1024,
        backupCount=10,
        encoding='utf-8'
    )
    json_handler.setLevel(logging.INFO)
    json_handler.setFormatter(JSON_FORMAT)
    json_logger.addHandler(json_handler)
    
    return json_logger

def setup_module_logger(module_name):
    """
    Setup logger for specific module with its own file
    """
    module_logger = logging.getLogger(module_name)
    module_logger.setLevel(logging.DEBUG)
    
    module_handler = logging.handlers.RotatingFileHandler(
        filename=LOG_DIR / f'{module_name}.log',
        maxBytes=20 * 1024 * 1024,
        backupCount=5,
        encoding='utf-8'
    )
    module_handler.setLevel(logging.DEBUG)
    module_handler.setFormatter(DETAILED_FORMAT)
    module_logger.addHandler(module_handler)
    
    return module_logger

def setup_syslog_handler(address=('localhost', 514)):
    """
    Setup syslog handler for remote logging
    """
    root_logger = logging.getLogger()
    
    syslog_handler = logging.handlers.SysLogHandler(address=address)
    syslog_handler.setLevel(logging.WARNING)
    syslog_handler.setFormatter(SIMPLE_FORMAT)
    root_logger.addHandler(syslog_handler)
    
    return syslog_handler

def setup_smtp_handler(mailhost, fromaddr, toaddrs, subject, credentials=None):
    """
    Setup email handler for critical errors
    """
    root_logger = logging.getLogger()
    
    smtp_handler = logging.handlers.SMTPHandler(
        mailhost=mailhost,
        fromaddr=fromaddr,
        toaddrs=toaddrs,
        subject=subject,
        credentials=credentials,
        secure=()
    )
    smtp_handler.setLevel(logging.CRITICAL)
    smtp_handler.setFormatter(DETAILED_FORMAT)
    root_logger.addHandler(smtp_handler)
    
    return smtp_handler

def setup_memory_handler(target_handler, capacity=1000):
    """
    Setup memory handler for buffered logging
    """
    root_logger = logging.getLogger()
    
    memory_handler = logging.handlers.MemoryHandler(
        capacity=capacity,
        flushLevel=logging.ERROR,
        target=target_handler
    )
    memory_handler.setLevel(logging.DEBUG)
    root_logger.addHandler(memory_handler)
    
    return memory_handler

