def log_application_event(message, level='info', **kwargs):
    """Log application events with additional context"""
    log_func = getattr(logger, level.lower(), logger.info)
    extra_info = ' - '.join([f'{k}={v}' for k, v in kwargs.items()])
    if extra_info:
        log_func(f'{message} - {extra_info}')
    else:
        log_func(message)

